  } catch (err) {
    // Even if pathfinding fails or is interrupted, we continue to the defensive stance if possible
  }

  // Defensive loop
  while (canContinue()) {
    if (bot.physicsEnabled) {
      // Maintain sneak (kneel)
      bot.setControlState('sneak', true);

      // Orient towards nearest potential threat
      const threat = bot.nearestEntity(function (e) {
        return (e.type === 'mob' || e.type === 'player') && e.id !== bot.entity.id && e.position.distanceTo(bot.entity.position) < 15;
      });

